private class CustomGLSurfaceView(context: Context) : GLSurfaceView(context) {
    var onSizeChangedCallback: ((Int, Int) -> Unit)? = null

    override fun onSizeChanged(w: Int, h: Int, oldw: Int, oldh: Int) {
        super.onSizeChanged(w, h, oldw, oldh)
        onSizeChangedCallback?.invoke(w, h)
    }
}

@Composable
private fun MeasurementSquareToolGlyph(centerColor: Color) {
    Box(contentAlignment = Alignment.Center) {
        Icon(
            imageVector = Icons.Filled.CenterFocusStrong,
            contentDescription = null,
            tint = MaterialTheme.colorScheme.onSurface
        )
        Box(
            modifier = Modifier
                .size(8.dp)
                .clip(CircleShape)
                .background(centerColor)
                .border(1.dp, Color.White, CircleShape)
        )
    }
}

@Composable
private fun MeasurementSpotToolGlyph(centerColor: Color = Color.Red) {
    Box(contentAlignment = Alignment.Center) {
        Icon(
            imageVector = Icons.Filled.GpsFixed,
            contentDescription = null,
            tint = MaterialTheme.colorScheme.onSurface
        )
        Box(
            modifier = Modifier
                .size(8.dp)
                .clip(CircleShape)
                .background(centerColor)
                .border(1.dp, Color.White, CircleShape)
        )
    }
}

@Composable
private fun TaskBarButton(
    active: Boolean = false,
    onClick: () -> Unit,
    content: @Composable () -> Unit
) {
    Surface(
        shape = CircleShape,
        color = if (active) MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.95f) else MaterialTheme.colorScheme.surface.copy(alpha = 0.55f),
        tonalElevation = if (active) 5.dp else 1.dp,
        shadowElevation = if (active) 2.dp else 0.dp,
        modifier = Modifier.border(
            width = 1.dp,
            color = if (active) Color.Black.copy(alpha = 0.35f) else Color.Transparent,
            shape = CircleShape
        )
    ) {
        IconButton(
            onClick = onClick,
            modifier = Modifier.size(40.dp)
        ) {
            content()
        }
    }
}

@Composable
private fun RecentThermogramThumbnail(
    imagePath: String,
    onOpen: () -> Unit,
    onRemove: () -> Unit
) {
    val imageBitmap by produceState<androidx.compose.ui.graphics.ImageBitmap?>(initialValue = null, key1 = imagePath) {
        value = withContext(Dispatchers.IO) {
            BitmapFactory.decodeFile(imagePath)?.asImageBitmap()
        }
    }

    Box(
        modifier = Modifier
            .size(72.dp)
            .clip(RoundedCornerShape(8.dp))
            .border(1.dp, Color.White.copy(alpha = 0.6f), RoundedCornerShape(8.dp))
            .background(Color.Black.copy(alpha = 0.5f))
            .clickable(onClick = onOpen)
    ) {
        if (imageBitmap != null) {
            Image(
                bitmap = imageBitmap!!,
                contentDescription = "Thumbnail",
                modifier = Modifier.fillMaxSize()
            )
        } else {
            Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                CircularProgressIndicator(modifier = Modifier.size(18.dp), strokeWidth = 2.dp)
            }
        }
        // Removed delete button (x)
        // onRemove não é usado, mas mantido para compatibilidade de assinatura
    }
}

fun syncMeasurementStates(
    viewModel: ThermogramCameraViewModel,
    sp1State: MeasurementSpotState,
    bx1State: MeasurementSquareState,
    bx2State: MeasurementSquareState
) {
    // Só envia os MeasurementSquares para o controller
    viewModel.setMeasurementSquareStates(listOf(sp1State, bx1State, bx2State))
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun ThermogramsCameraScreen(
    navController: NavHostController,
    viewModel: ThermogramCameraViewModel = hiltViewModel()
) {

    LaunchedEffect(navController) { /* no-op: keep navController referenced for now */ }

    // Get the activity context
    val context = LocalContext.current
    val activity = remember(context) { 
        context as? Activity ?: error("Context must be an Activity for screen capture")
    }

    // snapshot counter local state
    val recentThermograms by viewModel.recentThermograms.collectAsState()
    var showSnapshotButton by remember { mutableStateOf(true) }

    // Toggle states for toolbar buttons
    var isThermalMode by remember { mutableStateOf(false) }
    var isFlashOn by remember { mutableStateOf(false) }
    var isLaserOn by remember { mutableStateOf(false) }
    var sp1State by remember { mutableStateOf(MeasurementSpotState(label = "Sp1",enabled = true)) }
    var bx1State by remember { mutableStateOf(MeasurementSquareState(label = "Bx1", enabled = false)) }
    var bx2State by remember { mutableStateOf(MeasurementSquareState(label = "Ref")) }
    var measurementOverlaySize by remember { mutableStateOf(IntSize.Zero) }

    val snackbarHostState = remember { SnackbarHostState() }
    val scope = rememberCoroutineScope()

    val measurementTemperatures by viewModel.measurementTemperatures.collectAsState()
    val tempRange by viewModel.temperatureRange.collectAsState()


    LaunchedEffect(recentThermograms) {
        viewModel.pruneMissingRecentThermograms()
    }

    BoxWithConstraints(
        modifier = Modifier
            .fillMaxSize()
            .background(Color.White)
    ) {
        val temperatureBarWidth = (maxWidth * 0.038f).coerceIn(14.dp, 18.dp)
        val temperatureBarHeight = (maxHeight * 0.60f).coerceIn(270.dp, 414.dp) // Reduzido em ~12%
        val temperatureLabelShape = MaterialTheme.shapes.small
        val toolbarHeight = 56.dp
        val recentStripHeight = 90.dp
        val bottomReservedHeight = toolbarHeight + recentStripHeight

        // GLSurfaceView with renderer
        AndroidView(
            factory = { context: Context ->
                CustomGLSurfaceView(context).apply {
                    setEGLContextClientVersion(3)
                    preserveEGLContextOnPause = false
                    onSizeChangedCallback = { w: Int, h: Int ->
                        viewModel.onSurfaceSizeChanged(w, h)
                    }
                    viewModel.attachGlSurface(this)
                    viewModel.start()
//                    viewModel.startStream()
                }
            },
            modifier = Modifier
                .fillMaxSize()
                .background(color = Color.White)
        )

        // Keep overlays above toolbar + recent strip area.
        val measurementModeBottomPadding = bottomReservedHeight + 16.dp

        Box(
            modifier = Modifier
                .fillMaxSize()
                .padding(bottom = measurementModeBottomPadding)
                .onSizeChanged { measurementOverlaySize = it }
        ) {
            if (sp1State.enabled) {
                MeasurementSpotOverlay(
                    state = sp1State,
                    overlaySize = measurementOverlaySize,
                    onStateChange = {
                        sp1State = it;
                        syncMeasurementStates(viewModel, sp1State, bx1State, bx2State)
                    }
                )
            }
            MeasurementSquareOverlay(
                state = bx1State,
                overlaySize = measurementOverlaySize,
                onStateChange = { bx1State = it;
                    syncMeasurementStates(viewModel, sp1State, bx1State, bx2State) }
            )
            MeasurementSquareOverlay(
                state = bx2State,
                overlaySize = measurementOverlaySize,
                onStateChange = { bx2State = it;
                    syncMeasurementStates(viewModel, sp1State, bx1State, bx2State) }
            )
        }

        //Barra lateral com o range temperaturas
        Box(
            modifier = Modifier
                .fillMaxSize()
                .padding(end = 2.dp,top = 8.dp),
            contentAlignment = Alignment.TopEnd
        ) {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(end = 4.dp),
                horizontalAlignment = Alignment.End

            ) {
                val maxText = tempRange?.max?.let { String.format(Locale.getDefault(), "%.1f", it) } ?: "--"
                val minText = tempRange?.min?.let { String.format(Locale.getDefault(), "%.1f", it) } ?: "--"

                Surface(
                    color = Color(0xB0000000),
                    shape = temperatureLabelShape,
                    modifier = Modifier.border(1.dp, Color.White, temperatureLabelShape)
                ) {
                    Text(
                        text = maxText,
                        color = Color.White,
                        style = MaterialTheme.typography.labelLarge,
                        modifier = Modifier.padding(horizontal = 8.dp, vertical = 4.dp)
                    )
                }

                Spacer(modifier = Modifier.height(6.dp))

                Box(
                    modifier = Modifier
                        .width(temperatureBarWidth)
                        .height(temperatureBarHeight)
                        .clip(temperatureLabelShape)
                        .border(1.dp, Color.White, temperatureLabelShape)
                        .background(
                            Brush.verticalGradient(
                                colors = listOf(
                                    Color(0xFFFFF6C2), // quase branco (topo)
                                    Color(0xFFFFE066), // amarelo claro
                                    Color(0xFFFFB347), // amarelo/laranja
                                    Color(0xFFFF7A1A), // laranja forte
                                    Color(0xFFE53935), // vermelho
                                    Color(0xFF8E24AA), // roxo
                                    Color(0xFF3949AB), // azul
                                    Color(0xFF0D1B2A)  // azul escuro (base)
                                )
                            )
                        )
                ) {
                }

                Spacer(modifier = Modifier.height(6.dp))

                Surface(
                    color = Color(0xB0000000),
                    shape = temperatureLabelShape,
                    modifier = Modifier.border(1.dp, Color.White, temperatureLabelShape)
                ) {
                    Text(
                        text = minText,
                        color = Color.White,
                        style = MaterialTheme.typography.labelLarge,
                        modifier = Modifier.padding(horizontal = 8.dp, vertical = 4.dp)
                    )
                }

                Spacer(modifier = Modifier.height(8.dp))

                Surface(
                    color = Color(0xCC000000),
                    shape = CircleShape,
                    modifier = Modifier.border(1.dp, Color.White, CircleShape)
                ) {
                    IconButton(
                        onClick = { /* placeholder only: configure min/max later */ },
                        modifier = Modifier.size(34.dp)
                    ) {
                        Icon(
                            imageVector = Icons.Filled.Tune,
                            contentDescription = "Configure temperature range",
                            tint = Color.White,
                            modifier = Modifier.size(18.dp)
                        )
                    }
                }
            }
        }

        // Stop stream and disconnect when leaving the screen
        DisposableEffect(Unit) {
            onDispose {
                viewModel.stop()
            }
        }

        // Snackbar host
        Box(modifier = Modifier.fillMaxSize()) {
            SnackbarHost(
                hostState = snackbarHostState,
                modifier = Modifier
                    .align(Alignment.TopCenter)
                    .statusBarsPadding()
            )
        }

        //Botão de Snapshot
        Box(
            modifier = Modifier
                .fillMaxSize()
                .padding(bottom = bottomReservedHeight + 8.dp),
            contentAlignment = Alignment.BottomCenter
        ) {
            Box(contentAlignment = Alignment.Center) {

                if (showSnapshotButton) {
                    Box(
                        contentAlignment = Alignment.Center,
                        modifier = Modifier
                            .size(50.dp)
                            .clip(CircleShape)
                            .background(Color.Black)
                            .border(width = 2.dp, color = Color.LightGray, shape = CircleShape)
                    ) {
                        IconButton(onClick = {
                            showSnapshotButton = false
                            viewModel.takeSnapshotWithOverlay(activity) { success, msg, _ ->
                                scope.launch {
                                    showSnapshotButton = true
                                    if (success) {
//                                                snackbarHostState.showSnackbar("Snapshot with overlay saved")
                                    } else {
                                        snackbarHostState.showSnackbar("Snapshot failed: ${msg ?: "unknown"}")
                                    }
                                }
                            }
                        }) {
                            Icon(
                                imageVector = Icons.Filled.Camera,
                                contentDescription = "Snapshot",
                                tint = Color.White,
                                modifier = Modifier.size(50.dp)
                            )
                        }
                    }
                }
            }
        }

        //Toolbar
        Box(
            modifier = Modifier
                .fillMaxSize()
                .navigationBarsPadding(),
            contentAlignment = Alignment.BottomCenter
        ) {
            Column(
                modifier = Modifier.fillMaxWidth(),
                horizontalAlignment = Alignment.CenterHorizontally
            ) {
                Surface(
                    tonalElevation = 8.dp,
                    color = MaterialTheme.colorScheme.surface.copy(alpha = 0.95f),
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(toolbarHeight)
                ) {
                    Row(
                        modifier = Modifier
                            .fillMaxSize()
                            .padding(horizontal = 8.dp),
                        horizontalArrangement = Arrangement.SpaceEvenly,
                        verticalAlignment = Alignment.CenterVertically
                    ) {

                        // MeasurementSpot toggle button (Sp1)
                        TaskBarButton(active = sp1State.enabled, onClick = {
                            val newEnabled = !sp1State.enabled
                            sp1State = sp1State.copy(enabled = newEnabled)
                            if (newEnabled) {
                                bx1State = bx1State.copy(
                                    enabled = false,
                                    add = false,
                                    remove = true
                                )
                            }
                            syncMeasurementStates(viewModel, sp1State, bx1State, bx2State)
                        }) {
                            MeasurementSpotToolGlyph(centerColor = Color.Red)
                        }

                        // MeasurementRectangle toggle button (Bx1)
                        TaskBarButton(active = bx1State.enabled, onClick = {
                            val newEnabled = !bx1State.enabled
                            bx1State = bx1State.copy(
                                enabled = newEnabled,
                                add = newEnabled,
                                remove = !newEnabled
                            )
                            if (newEnabled) {
                                sp1State = sp1State.copy(
                                    enabled = false,
                                    add = false,
                                    remove = true
                                )
                            }
                            syncMeasurementStates(viewModel, sp1State, bx1State, bx2State)
                        }) {
                            MeasurementSquareToolGlyph(centerColor = Color.Red)
                        }

                        // MeasurementRectangle button (Bx2)
                        TaskBarButton(active = bx2State.enabled, onClick = {
                            val newEnabled = !bx2State.enabled
                            bx2State = bx2State.copy(
                                enabled = newEnabled,
                                add = newEnabled,
                                remove = !newEnabled
                            )
                            syncMeasurementStates(viewModel, sp1State, bx1State, bx2State)
                        }) {
                            MeasurementSquareToolGlyph(centerColor = Color(0xFF2196F3))
                        }

                        // Palette selector
                        var paletteMenuExpanded by remember { mutableStateOf(false) }
                        val currentPalette by viewModel.currentPalette.collectAsState()
                        val filteredPalettesWithLabel = viewModel.filteredPalettesWithLabel
                        TaskBarButton(onClick = { paletteMenuExpanded = true }, active = false) {
                            Icon(
                                imageVector = Icons.Filled.ColorLens,
                                contentDescription = "Palette",
                                tint = MaterialTheme.colorScheme.onSurface
                            )
                        }
                        DropdownMenu(
                            expanded = paletteMenuExpanded,
                            onDismissRequest = { paletteMenuExpanded = false },
                            // Remove o background padrão do menu
                            modifier = Modifier
                                .background(Color.Transparent)
                                .border(0.dp, Color.Transparent)
                        ) {
                            filteredPalettesWithLabel.forEach { (palette, label) ->
                                DropdownMenuItem(
                                    text = { Text(label) },
                                    onClick = {
                                        viewModel.selectPalette(palette)
                                        // Não fecha o dropdown ao selecionar
                                    },
                                    leadingIcon = {
                                        // Opcional: pode-se adicionar um preview gráfico da palette aqui
                                    },
                                    trailingIcon = {
                                        if (palette == currentPalette) {
                                            Icon(Icons.Filled.Check, contentDescription = null)
                                        }
                                    },
                                    modifier = Modifier.background(Color.Transparent)
                                )
                            }
                        }

                        // Flashlight toggle button
                        TaskBarButton(active = isFlashOn, onClick = {
                            viewModel.toggleFlash { success, msg ->
                                if (!success) {
                                    scope.launch { snackbarHostState.showSnackbar("Flash failed: $msg") }
                                } else {
                                    isFlashOn = !isFlashOn
                                }
                            }
                        }) {
                            Icon(
//                                imageVector = if (isFlashOn) Icons.Filled.FlashlightOn else Icons.Filled.FlashlightOn,
                                imageVector = Icons.Filled.FlashlightOn,
                                contentDescription = "Flashlight",
                                tint = if (isFlashOn) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurface
                            )
                        }

                        // Laser toggle button
                        TaskBarButton(active = isLaserOn, onClick = {
                            viewModel.toggleLaser { success, msg ->
                                if (!success) {
                                    scope.launch { snackbarHostState.showSnackbar("Laser failed: $msg") }
                                } else {
                                    isLaserOn = !isLaserOn
                                }
                            }
                        }) {
                            Icon(
                                imageVector = Icons.Filled.Flare,
                                contentDescription = "Laser",
                                tint = if (isLaserOn) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurface,
                            )
                        }

                        TaskBarButton(active = isThermalMode, onClick = { isThermalMode = !isThermalMode }) {
                            Icon(
                                imageVector = Icons.Filled.Settings,
                                contentDescription = "Settings",
                                tint = if (isThermalMode) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurface
                            )
                        }
                    }
                }

                // Always show the recent thermograms area with dark gray background and placeholder if empty
                val recentBarHeight = 72.dp
                Surface(
                    color = Color(0xFF23272A), // dark gray
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(recentBarHeight)
                ) {
                    if (recentThermograms.isEmpty()) {
                        Box(
                            modifier = Modifier.fillMaxSize(),
                            contentAlignment = Alignment.Center
                        ) {
                            Text(
                                text = "Termogramas Recentes...",
                                color = Color.LightGray,
                                style = MaterialTheme.typography.bodyMedium
                            )
                        }
                    } else {
                        Column(modifier = Modifier.padding(8.dp)) {
                            LazyRow(
                                horizontalArrangement = Arrangement.spacedBy(8.dp),
                                contentPadding = PaddingValues(horizontal = 4.dp)
                            ) {
                                items(recentThermograms) { imagePath ->
                                    RecentThermogramThumbnail(
                                        imagePath = imagePath,
                                        onOpen = {
                                            navController.currentBackStackEntry
                                                ?.savedStateHandle
                                                ?.set("thermogram_recent_list", ArrayList(recentThermograms))
                                            navController.navigate("${NavRoutes.THERMOGRAM_IMAGE}/${Uri.encode(imagePath)}")
                                        },
                                        onRemove = {
                                            viewModel.removeRecentThermogram(imagePath, deleteFile = true)
                                        }
                                    )
                                }
                            }
                        }
                    }
                }
            }
        }

        // Overlay watermark in bottom start above toolbar
        Box(
            modifier = Modifier.fillMaxSize(),
            contentAlignment = Alignment.BottomStart
        ) {
            WatermarkOverlay()
        }

        Box(
            modifier = Modifier
                .padding(start = 8.dp, top = 8.dp)
                .background(Color(0xCC000000), shape = RoundedCornerShape(8.dp))
                .border(1.dp, Color.White, RoundedCornerShape(8.dp))
                .padding(horizontal = 12.dp, vertical = 8.dp),
            contentAlignment = Alignment.TopStart
        ) {
            Column {
                val objTemp = measurementTemperatures.spot ?: measurementTemperatures.bx1
                val objLabel = if (sp1State.enabled) sp1State.label else bx1State.label
                if (objTemp != null) {
                    Text(
                        text = "$objLabel\t" + String.format(Locale.getDefault(), "%.1f\t°C", objTemp),
                        color = Color.White,
                        style = MaterialTheme.typography.labelLarge
                    )
                }

                // Se bx2 (Ref) estiver ativo, mostrar Ref e AT
                if (bx2State.enabled && measurementTemperatures.bx2 != null) {
                    Text(
                        text = "Ref\t" + (measurementTemperatures.bx2?.let { String.format(Locale.getDefault(), "%.1f\t°C", it) } ?: "--"),
                        color = Color.White,
                        style = MaterialTheme.typography.labelLarge
                    )
                    val objTemp = measurementTemperatures.spot ?: measurementTemperatures.bx1
                    val at = if (objTemp != null && measurementTemperatures.bx2 != null) objTemp - measurementTemperatures.bx2!! else null
                    Text(
                        text = "ΔT\t\t" + (at?.let { String.format(Locale.getDefault(), "%.1f\t°C", it) } ?: "--"),
                        color = Color.White,
                        style = MaterialTheme.typography.labelLarge
                    )
                }
            }
        }
    }
}

@Composable
private fun WatermarkOverlay(modifier: Modifier = Modifier) {
    Row(
        modifier = modifier
            .padding(start = 8.dp, bottom = 120.dp) // 100dp to sit above toolbar and recent bar
//            .background(Color(0x80000000), shape = RoundedCornerShape(12.dp))
            .padding(horizontal = 6.dp, vertical = 12.dp),
        verticalAlignment = Alignment.CenterVertically
    ) {
        Image(
            painter = painterResource(id = com.tech.thermography.android.R.drawable.logo_thermal_energy_vb),
            contentDescription = "Logo Thermal Energy",
            modifier = Modifier.size(60.dp)
        )
    }
}

package com.tech.thermography.android.ui.camera

import android.app.Activity
import android.content.Context
import android.opengl.GLSurfaceView
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext
import com.flir.thermalsdk.live.remote.StoredImage
import com.tech.thermography.android.flir.AceController
import com.tech.thermography.android.flir.AceController.TemperatureRange
import dagger.hilt.android.qualifiers.ApplicationContext
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.delay
import kotlinx.coroutines.isActive
import org.json.JSONArray
import java.io.File
import javax.inject.Inject

@HiltViewModel
class ThermogramCameraViewModel @Inject constructor(
    private val controller: AceController,
    @ApplicationContext private val context: Context
) : ViewModel() {

    companion object {
        private const val PREFS_NAME = "recent_thermograms"
        private const val KEY_RECENT = "recent_paths"
    }

    private val _recentThermograms = MutableStateFlow<List<String>>(emptyList())
    val recentThermograms: StateFlow<List<String>> = _recentThermograms.asStateFlow()


    //Atualização do estado de temperatura
    private val _measurementTemperatures = MutableStateFlow(MeasurementTemperatures())
    val measurementTemperatures: StateFlow<MeasurementTemperatures> = _measurementTemperatures.asStateFlow()

    //Atualização do range de temperatura
    private val _temperatureRange = MutableStateFlow(getTemperatureRange())
    val temperatureRange: StateFlow<TemperatureRange?> = _temperatureRange.asStateFlow()


    init {
        _recentThermograms.value = loadRecentThermograms().filter { File(it).exists() }
        persistRecentThermograms(_recentThermograms.value)

        startTemperaturesRangeUpdates()
        startMeasurementTemperaturesUpdates()
    }

    private fun startTemperaturesRangeUpdates() {
        viewModelScope.launch {
            while (isActive) {
                _temperatureRange.value = getTemperatureRange()
                delay(500)
            }
        }
    }

    private fun startMeasurementTemperaturesUpdates() {
        viewModelScope.launch {
            while (isActive) {
                _measurementTemperatures.value = getMeasurementTemperatures()!!
                delay(500)
            }
        }
    }

    fun attachGlSurface(glView: GLSurfaceView) {
        controller.attachSurface(glView)
    }

    fun onSurfaceSizeChanged(width: Int, height: Int) {
        controller.onSurfaceSizeChanged(width, height)
    }

    fun start() {
        controller.startCamera()
    }

    fun stop() {
        controller.disconnect()
    }

    override fun onCleared() {
        controller.disconnect()
    }


    /**
     * Requests the camera to store a snapshot WITH screen overlay (saved as separate PNG).
     * Creates 2 files: snapshot_XXX.jpg (thermal) + snapshot_XXX_overlay.png (UI)
     * The callback returns (success, message, storedImage?)
     */
    fun takeSnapshotWithOverlay(
        activity: Activity,
        callback: (Boolean, String?, StoredImage?) -> Unit = { _, _, _ -> }
    ) {
        controller.takeSnapshotWithOverlay(activity) { success, msg, storedImage ->
            if (success && !msg.isNullOrBlank()) {
                onSnapshotSaved(msg)
            }
            callback(success, msg, storedImage)
        }
    }

    fun onSnapshotSaved(path: String) {
        _recentThermograms.value = buildList {
            add(path)
            addAll(_recentThermograms.value.filterNot { it == path })
        }.filter { File(it).exists() }.take(20)
        persistRecentThermograms(_recentThermograms.value)
    }

    fun removeRecentThermogram(path: String, deleteFile: Boolean = true) {
        _recentThermograms.value = _recentThermograms.value.filterNot { it == path }
        persistRecentThermograms(_recentThermograms.value)

        if (deleteFile) {
            viewModelScope.launch(Dispatchers.IO) {
                runCatching { File(path).delete() }
            }
        }
    }

    fun pruneMissingRecentThermograms() {
        val filtered = _recentThermograms.value.filter { File(it).exists() }
        if (filtered != _recentThermograms.value) {
            _recentThermograms.value = filtered
            persistRecentThermograms(filtered)
        }
    }

    private fun persistRecentThermograms(paths: List<String>) {
        val payload = JSONArray().apply { paths.forEach { put(it) } }.toString()
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
            .edit()
            .putString(KEY_RECENT, payload)
            .apply()
    }

    private fun loadRecentThermograms(): List<String> {
        val raw = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
            .getString(KEY_RECENT, null)
            ?: return emptyList()
        return runCatching {
            val array = JSONArray(raw)
            buildList {
                for (i in 0 until array.length()) {
                    val path = array.optString(i)
                    if (path.isNotBlank()) add(path)
                }
            }
        }.getOrElse { emptyList() }
    }

    fun toggleLaser(callback: (Boolean, String?) -> Unit = { _, _ -> }) {
        controller.toggleLaser(callback)
    }

    fun toggleFlash(callback: (Boolean, String?) -> Unit = { _, _ -> }) {
        controller.toggleLamp(callback)
    }

    fun getTemperatureRange(): AceController.TemperatureRange? {
        return controller.getTemperatureRange()
    }

    fun getMeasurementTemperatures(): MeasurementTemperatures? {
        return controller.getMeasurementTemperatures()
    }

    fun setMeasurementSquareStates(states: List<MeasurementState>) {
        controller.setMeasurementStates(states)
    }
}

package com.tech.thermography.android.ui.camera

import android.app.Activity
import android.content.Context
import android.opengl.GLSurfaceView
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext
import com.flir.thermalsdk.live.remote.StoredImage
import com.tech.thermography.android.flir.AceController
import com.tech.thermography.android.flir.AceController.TemperatureRange
import dagger.hilt.android.qualifiers.ApplicationContext
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.delay
import kotlinx.coroutines.isActive
import org.json.JSONArray
import java.io.File
import javax.inject.Inject

@HiltViewModel
class ThermogramCameraViewModel @Inject constructor(
    private val controller: AceController,
    @ApplicationContext private val context: Context
) : ViewModel() {
    // Palettes disponíveis
    private val _palettes = MutableStateFlow<List<com.flir.thermalsdk.image.Palette>>(emptyList())
    val palettes: StateFlow<List<com.flir.thermalsdk.image.Palette>> = _palettes.asStateFlow()

    // Palette selecionada
    private val _currentPalette = MutableStateFlow<com.flir.thermalsdk.image.Palette?>(null)
    val currentPalette: StateFlow<com.flir.thermalsdk.image.Palette?> = _currentPalette.asStateFlow()

    companion object {
        private const val PREFS_NAME = "recent_thermograms"
        private const val KEY_RECENT = "recent_paths"
        // Mapa de nomes de palette para labels amigáveis
        val PALETTE_LABELS = mapOf(
            "iron" to "Ferro",
            "lava" to "Lava",
            "rainbow" to "Arco-Íris",
            "rainhc" to "Elevado Contraste de Arco-Íris",
            "artic" to "Ártico",
            "whitehot" to "Incandescente Branco",
            "blackhot" to "Incandescente Preto"
        )
    }

    private val _recentThermograms = MutableStateFlow<List<String>>(emptyList())
    val recentThermograms: StateFlow<List<String>> = _recentThermograms.asStateFlow()

    // Lista reduzida de palettes com label amigável, ordenada conforme a ordem do mapa
    val filteredPalettesWithLabel: List<Pair<com.flir.thermalsdk.image.Palette, String>>
        get() {
            val paletteOrder = PALETTE_LABELS.keys.toList()
            val filtered = _palettes.value.mapNotNull { palette ->
                val nameKey = palette.name?.replace(" ", "")?.lowercase() ?: return@mapNotNull null
                val label = PALETTE_LABELS[nameKey]
                if (label != null) palette to label else null
            }
            // Ordena conforme a ordem do mapa
            return paletteOrder.flatMap { key ->
                filtered.filter { (palette, _) ->
                    palette.name?.replace(" ", "")?.lowercase() == key
                }
            }
        }


    //Atualização do estado de temperatura
    private val _measurementTemperatures = MutableStateFlow(MeasurementTemperatures())
    val measurementTemperatures: StateFlow<MeasurementTemperatures> = _measurementTemperatures.asStateFlow()

    //Atualização do range de temperatura
    private val _temperatureRange = MutableStateFlow(getTemperatureRange())
    val temperatureRange: StateFlow<TemperatureRange?> = _temperatureRange.asStateFlow()


    init {
        // Inicializa lista de palettes e seleciona a primeira como padrão
        val defaultPalettes = com.flir.thermalsdk.image.PaletteManager.getDefaultPalettes()
        _palettes.value = defaultPalettes
        _currentPalette.value = defaultPalettes.firstOrNull()
        _currentPalette.value?.let { controller.setCurrentPalette(it) }
        _recentThermograms.value = loadRecentThermograms().filter { File(it).exists() }
        persistRecentThermograms(_recentThermograms.value)

        startTemperaturesRangeUpdates()
        startMeasurementTemperaturesUpdates()
    }

    fun selectPalette(palette: com.flir.thermalsdk.image.Palette) {
        _currentPalette.value = palette
        controller.setCurrentPalette(palette)
    }

    private fun startTemperaturesRangeUpdates() {
        viewModelScope.launch {
            while (isActive) {
                _temperatureRange.value = getTemperatureRange()
                delay(500)
            }
        }
    }

    private fun startMeasurementTemperaturesUpdates() {
        viewModelScope.launch {
            while (isActive) {
                _measurementTemperatures.value = getMeasurementTemperatures()!!
                delay(500)
            }
        }
    }

    fun attachGlSurface(glView: GLSurfaceView) {
        controller.attachSurface(glView)
    }

    fun onSurfaceSizeChanged(width: Int, height: Int) {
        controller.onSurfaceSizeChanged(width, height)
    }

    fun start() {
        controller.startCamera()
    }

    fun stop() {
        controller.disconnect()
    }

    override fun onCleared() {
        controller.disconnect()
    }


    /**
     * Requests the camera to store a snapshot WITH screen overlay (saved as separate PNG).
     * Creates 2 files: snapshot_XXX.jpg (thermal) + snapshot_XXX_overlay.png (UI)
     * The callback returns (success, message, storedImage?)
     */
    fun takeSnapshotWithOverlay(
        activity: Activity,
        callback: (Boolean, String?, StoredImage?) -> Unit = { _, _, _ -> }
    ) {
        controller.takeSnapshotWithOverlay(activity) { success, msg, storedImage ->
            if (success && !msg.isNullOrBlank()) {
                onSnapshotSaved(msg)
            }
            callback(success, msg, storedImage)
        }
    }

    fun onSnapshotSaved(path: String) {
        _recentThermograms.value = buildList {
            add(path)
            addAll(_recentThermograms.value.filterNot { it == path })
        }.filter { File(it).exists() }.take(20)
        persistRecentThermograms(_recentThermograms.value)
    }

    fun removeRecentThermogram(path: String, deleteFile: Boolean = true) {
        _recentThermograms.value = _recentThermograms.value.filterNot { it == path }
        persistRecentThermograms(_recentThermograms.value)

        if (deleteFile) {
            viewModelScope.launch(Dispatchers.IO) {
                runCatching { File(path).delete() }
            }
        }
    }

    fun pruneMissingRecentThermograms() {
        val filtered = _recentThermograms.value.filter { File(it).exists() }
        if (filtered != _recentThermograms.value) {
            _recentThermograms.value = filtered
            persistRecentThermograms(filtered)
        }
    }

    private fun persistRecentThermograms(paths: List<String>) {
        val payload = JSONArray().apply { paths.forEach { put(it) } }.toString()
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
            .edit()
            .putString(KEY_RECENT, payload)
            .apply()
    }

    private fun loadRecentThermograms(): List<String> {
        val raw = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
            .getString(KEY_RECENT, null)
            ?: return emptyList()
        return runCatching {
            val array = JSONArray(raw)
            buildList {
                for (i in 0 until array.length()) {
                    val path = array.optString(i)
                    if (path.isNotBlank()) add(path)
                }
            }
        }.getOrElse { emptyList() }
    }

    fun toggleLaser(callback: (Boolean, String?) -> Unit = { _, _ -> }) {
        controller.toggleLaser(callback)
    }

    fun toggleFlash(callback: (Boolean, String?) -> Unit = { _, _ -> }) {
        controller.toggleLamp(callback)
    }

    fun getTemperatureRange(): AceController.TemperatureRange? {
        return controller.getTemperatureRange()
    }

    fun getMeasurementTemperatures(): MeasurementTemperatures? {
        return controller.getMeasurementTemperatures()
    }

    fun setMeasurementSquareStates(states: List<MeasurementState>) {
        controller.setMeasurementStates(states)
    }
}
